cssCustomProperties:
/* === PEGAR DENTRO DE @theme {} EN resources/css/app.css === */

  /* Colores GraciasMadre */
  --color-mama-rose: #FFD6E0;
  --color-mama-rose-soft: #FFB8D0;
  --color-mama-rose-deep: #F4A0BF;
  --color-mama-lavender: #E8D5F5;
  --color-mama-lavender-deep: #C9A8E8;
  --color-mama-peach: #FFE4BA;
  --color-mama-peach-deep: #FFCB8A;
  --color-mama-cream: #FFF9F5;
  --color-mama-text: #4A3728;
  --color-mama-text-light: #7A6358;
  --color-mama-cta: #D4467A;
  --color-mama-cta-hover: #B8336A;
  --color-mama-gold: #F0C060;
  --color-mama-green: #A8D8A8;
  --color-mama-green-deep: #8DB87A;

  /* Tipografías */
  --font-display: 'Playfair Display', Georgia, 'Times New Roman', serif;
  --font-body: 'Nunito', system-ui, sans-serif;

  /* Animaciones personalizadas (referencia a keyframes definidos fuera de @theme) */
  --animate-float: float 4s ease-in-out infinite;
  --animate-float-delayed: float-delayed 4s ease-in-out 2s infinite;
  --animate-bloom: bloom 0.9s ease-out both;
  --animate-pulse-heart: pulse-heart 1.4s ease-in-out infinite;
  --animate-petal-fall: petal-fall 6s ease-in infinite;
  --animate-shimmer: shimmer 3s linear infinite;

cssKeyframes:
/* === PEGAR FUERA DE @theme {}, DESPUÉS DEL BLOQUE, EN resources/css/app.css === */

@keyframes float {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  33%       { transform: translateY(-14px) rotate(4deg); }
  66%       { transform: translateY(-7px) rotate(-3deg); }
}

@keyframes float-delayed {
  0%, 100% { transform: translateY(0px) rotate(0deg); }
  33%       { transform: translateY(-12px) rotate(-4deg); }
  66%       { transform: translateY(-6px) rotate(3deg); }
}

@keyframes bloom {
  0%   { transform: scale(0) rotate(-180deg); opacity: 0; }
  60%  { transform: scale(1.12) rotate(8deg); opacity: 1; }
  100% { transform: scale(1) rotate(0deg);   opacity: 1; }
}

@keyframes pulse-heart {
  0%, 100% { transform: scale(1); }
  50%      { transform: scale(1.18); }
}

@keyframes petal-fall {
  0%   { transform: translateY(-30px) rotate(0deg) translateX(0); opacity: 1; }
  100% { transform: translateY(110vh) rotate(720deg) translateX(40px); opacity: 0; }
}

@keyframes shimmer {
  0%   { background-position: -200% center; }
  100% { background-position: 200% center; }
}

jsImports.appJs:
import Alpine from 'alpinejs';
import AOS from 'aos';
import 'aos/dist/aos.css';

window.Alpine = Alpine;
Alpine.start();

document.addEventListener('DOMContentLoaded', () => {
  AOS.init({
    duration: 800,
    easing: 'ease-out-cubic',
    once: true,
    offset: 80
  });
});
